#include <nthread-impl.h>
#include "subasta.h"

// =============================================================
// Implementacion de la subasta multi-threaded
// Supuesto: timeout se expresa en milisegundos (como en los tests).
// =============================================================

typedef struct oferta Oferta;

struct oferta {
  nThread th;
  double precio;
  unsigned long long seq;
  int win;
  int linked;
  Oferta *prev;
  Oferta *next;
};

struct subasta {
  int unidades;
  int cerrada;
  int pendientes;
  double recaudado;
  unsigned long long nextSeq;
  Oferta *head;
  Oferta *tail;
};

static void oferta_detach(nSubasta s, Oferta *o) {
  if (o==NULL || !o->linked)
    return;

  if (o->prev!=NULL)
    o->prev->next= o->next;
  else
    s->head= o->next;

  if (o->next!=NULL)
    o->next->prev= o->prev;
  else
    s->tail= o->prev;

  o->prev= NULL;
  o->next= NULL;
  o->linked= 0;
  s->pendientes--;
}

static void oferta_insertar(nSubasta s, Oferta *o) {
  Oferta *cur= s->head;
  Oferta *prev= NULL;

  while (cur!=NULL && cur->precio >= o->precio) {
    prev= cur;
    cur= cur->next;
  }

  o->prev= prev;
  o->next= cur;
  o->linked= 1;

  if (prev!=NULL)
    prev->next= o;
  else
    s->head= o;

  if (cur!=NULL)
    cur->prev= o;
  else
    s->tail= o;

  s->pendientes++;
}

static void oferta_wake(nSubasta s, Oferta *o, int win) {
  if (o->th->status==WAIT_SUBASTA_TIMEOUT)
    nth_cancelThread(o->th);
  o->win= win;
  setReady(o->th);
}

static void timeout_subasta(nThread th) {
  Oferta *o= th->ptr;
  if (o==NULL || !o->linked)
    return;
  if (o->win)
    return;
  o->win= FALSE;
